import React from "react";
import { Link, useLocation } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";

const ROL_ADMIN = 1;

const Navbar = ({ loggedInUser, isMobileMenuOpen, toggleMobileMenu }) => {
  const location = useLocation();

  const baseLinks = [
    { label: "NOSOTROS", path: "/historia" },
    { label: "EQUIPO", path: "/equipo" },
    { label: "INICIO", path: "/" },
    { label: "REVISTA", path: "/revistaPage" },

     // Nueva entrada agregada
    { label: "EMPRESAS", path: "/empresas" },
    { label: "CONTACTO", path: "/contacto" },
  ];

  let finalLinks = [...baseLinks];
  if (loggedInUser && loggedInUser.id_rol === ROL_ADMIN) {
    finalLinks.push({ label: "ADMIN USUARIOS", path: "/panel-usuarios" });
    finalLinks.push({ label: "DASHBOARDS", path: "/dashboards" });
  }

  const menuVariants = {
    hidden: { opacity: 0, y: -50 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.3 } },
    exit: { opacity: 0, y: -50, transition: { duration: 0.3 } },
  };

  return (
    <>
      {/* Navbar only visible in desktop/tablet, completely hidden in mobile */}
      <motion.nav
        className="w-full fixed top-24 z-50 md:flex hidden items-center justify-center bg-surface-elevated/95 backdrop-blur-sm border-b border-stroke shadow-sm py-4 px-6 md:px-10 lg:px-20"
        initial={{ y: -50, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6 }}
      >
        {/* ...existing code... */}
      </motion.nav>

      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            className="fixed inset-0 bg-surface-elevated/95 backdrop-blur-sm z-40 flex flex-col items-center justify-center space-y-6 md:hidden"
            variants={menuVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
          >
            <button
              onClick={toggleMobileMenu}
              className="absolute top-4 right-6 rounded-full w-12 h-12 flex items-center justify-center shadow-md"
              style={{ background: '#072D42', border: 'none', color: '#FEFCFB', fontSize: '2.5rem', fontWeight: 'bold', zIndex: 9999 }}
              aria-label="Cerrar menú"
            >
              ×
            </button>
            {finalLinks.map((item, index) => {
              const isActive = location.pathname === item.path;
              return (
                <motion.div
                  key={index}
                  whileHover={!isActive ? { scale: 1.1 } : {}}
                  whileTap={{ scale: 0.9 }}
                >
                  <Link
                    to={item.path}
                    className={`font-miles text-xl font-medium tracking-wide relative pb-1 select-none inline-block transition-all duration-200 no-underline hover:no-underline ${
                      isActive
                        ? "text-primary font-semibold cursor-default hover:text-primary"
                        : "text-text-main cursor-pointer hover:text-accent"
                    }`}
                    onClick={toggleMobileMenu}
                  >
                    {item.label}
                    {/* Subrayado solo para página activa */}
                    {isActive && (
                      <motion.div
                        layoutId="underline-mobile"
                        className="h-1 bg-primary rounded-md absolute bottom-0 left-0 right-0"
                        initial={{ width: 0 }}
                        animate={{ width: "100%" }}
                        transition={{ duration: 0.3 }}
                      />
                    )}
                  </Link>
                </motion.div>
              );
            })}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Navbar;
